-- 1. Dover × Web Design
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'web-design',
  'dover',
  'Dover occupies a unique position in Kent as both an ancient historic town and the busiest passenger port in the United Kingdom. Every year, millions of travellers pass through the Port of Dover on their way to and from mainland Europe, yet the town itself has struggled to retain that footfall and convert passing visitors into local customers. With a population of around thirty-five thousand in the town and over one hundred and seventeen thousand across the district, Dover businesses serve a mix of residents, tourists drawn to Dover Castle and the White Cliffs, and the logistics and transport workforce that keeps the port running. A professionally built website is essential for capturing these diverse audiences. We design conversion-focused websites for Dover businesses that speak to tourists researching visits, residents searching for local services, and commercial clients across the port and transport sector.',
  'Dover''s commercial geography is shaped by its port and heritage. The town centre around Market Square and the High Street serves as the retail core, while the seafront and De Bradelei Wharf attract tourist footfall. Dover Castle and the White Cliffs draw hundreds of thousands of visitors annually, generating demand for hospitality, dining, and retail. The A2 and A20 corridors connect Dover to London and the M25, making the town a gateway for continental logistics. Dover Priory station links to London St Pancras via high-speed rail. The Western Heights and Connaught Park add residential character to the hillside areas above the town centre.',
  'Dover''s web design market is underserved. Many businesses around Market Square and the High Street operate with dated websites that fail to capture the tourist audience effectively. Port-related logistics firms often have functional but visually uninspiring sites. Tourism operators near the Castle and White Cliffs vary significantly in digital quality. London agencies rarely target Dover specifically, leaving a gap between cheap template builders and genuine quality.',
  'Our approach for Dover starts with understanding the three distinct audiences every business here must consider: local residents, tourists and visitors, and the port and logistics sector. We build sites that serve each audience with clear navigation paths, whether someone is a local searching for a plumber on Market Square, a tourist planning a White Cliffs walk, or a shipping company evaluating a logistics partner. Speed and mobile optimisation are critical for the tourist audience browsing on mobile data.',
  '{"population": 35000, "district_population": 117000, "business_districts": ["Market Square", "High Street", "De Bradelei Wharf", "Port of Dover", "Dover Priory area"], "key_fact": "Busiest passenger port in the UK with millions of annual travellers"}',
  '[{"title": "Tourist traffic not converting into local business online", "description": "Hundreds of thousands of visitors come to Dover Castle and the White Cliffs each year. They search for restaurants, shops, and experiences on their phones while visiting. Dover businesses with outdated, slow websites lose these visitors to the handful of competitors who present a polished digital experience."}, {"title": "Dated websites failing to compete across three audiences", "description": "Dover businesses must appeal to residents, tourists, and the port logistics sector simultaneously. Most existing websites were built for one audience and ignore the others entirely. A restaurant near Market Square needs to attract both locals and Castle visitors, but its five-year-old site does neither effectively."}, {"title": "Port and logistics firms lacking professional digital presence", "description": "The transport and logistics sector around the Port of Dover is substantial, yet many firms operate with basic brochure websites that do not convey the scale or professionalism of their operations. When international clients search for Dover-based logistics partners, a substandard website costs contracts."}]',
  '[{"title": "Multi-audience websites designed for Dover''s unique market", "description": "We build Dover websites with distinct user journeys for each audience. Tourists get prominent booking and visiting information with stunning White Cliffs imagery. Local residents get clear service pages and easy contact methods. Commercial clients get professional capability presentations. One site, three conversion paths."}, {"title": "Mobile-first design for on-the-go tourist visitors", "description": "Visitors walking along the White Cliffs or queuing at the port browse exclusively on mobile. We build Dover sites with sub-two-second mobile load times, thumb-friendly navigation, and prominent click-to-call buttons. Your site works flawlessly on patchy mobile signal near the clifftops."}, {"title": "Professional websites that match Dover''s heritage significance", "description": "Dover is a town of genuine historic importance, from the Castle to St Edmund''s Chapel to the Western Heights. We design sites that reflect this heritage credibility without feeling dated. Your business benefits from Dover''s prestige through design that communicates permanence and trustworthiness."}]',
  '[{"question": "How long does a new website take for a Dover business?", "answer": "Most Dover projects launch within four to six weeks. We begin with a strategy session understanding your position in the local market, whether you serve tourists near the Castle, residents around Market Square, or commercial clients linked to the port. Design, development, and testing follow a structured timeline."}, {"question": "Will my site attract both tourists and local customers?", "answer": "Yes. We design Dover websites with separate user journeys for different audiences. A restaurant might have a tourist landing page highlighting proximity to the Castle and White Cliffs alongside a locals page featuring weekly menus and booking. Each audience sees content relevant to their needs."}, {"question": "Can you help my logistics business look more professional online?", "answer": "Absolutely. We work with several Dover businesses in the port and transport sector. We build websites that project the operational scale and professionalism international clients expect, with case studies, fleet information, and capability presentations that win contracts."}, {"question": "Do you work with businesses outside Dover town centre?", "answer": "Yes. We serve businesses across the Dover district including Deal, Sandwich, and surrounding villages. Our local SEO approach ensures your site reaches customers across the A2 and A20 corridors and the wider east Kent area."}]',
  'lead-gen'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
