-- 6. Dover × Social Media Setup
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'social-media-setup',
  'dover',
  'Social media in Dover operates on two distinct levels. The local community discusses businesses, recommends tradespeople, and shares experiences in Dover-specific Facebook groups. Simultaneously, visitors and tourists post about the White Cliffs, Dover Castle, and port crossings across Instagram, TripAdvisor, and Facebook, generating enormous volumes of Dover-related content that local businesses could leverage but almost never do. A restaurant near Market Square that is tagged in a tourist''s White Cliffs Instagram post gains exposure to hundreds of potential visitors, but only if its profile is properly set up, branded, and active. We build and optimise social media profiles for Dover businesses that capture both the local community conversation and the visitor-driven content that makes this town unique.',
  'Dover''s social media landscape combines strong local community engagement with high-volume tourist content. Facebook groups for Dover residents are active forums for recommendations and reviews. Instagram sees significant Dover content driven by the White Cliffs and Castle, with visitor photos generating thousands of impressions daily. TripAdvisor is heavily used for Dover hospitality businesses given the tourist footfall. Google reviews influence both local search rankings and tourist decision-making. The port generates its own social conversation around crossing times, delays, and travel experiences.',
  'Social media quality among Dover businesses is inconsistent. Tourism-facing businesses near the Castle tend to have active Instagram presences, but most other Dover businesses either have dormant Facebook pages or no social media at all. Few businesses engage with the tourist content being created about Dover daily. The gap between businesses with professional social media and those without is widening as customers increasingly check social profiles before making purchasing decisions.',
  'We set up Dover social media profiles based on audience behaviour. Hospitality and tourism businesses get Instagram-first strategies to intercept visitor content. Trades and local services get Facebook profiles optimised for community group engagement. Port and logistics firms get LinkedIn pages built for commercial credibility. Every profile is branded consistently and includes Dover-specific local information that improves discoverability.',
  '{"population": 35000, "district_population": 117000, "business_districts": ["Market Square", "High Street", "De Bradelei Wharf", "Dover Castle area"], "key_fact": "High-volume tourist social content creates unique engagement opportunities"}',
  '[{"title": "Tourist social content going unmonetised by Dover businesses", "description": "Visitors to the White Cliffs and Dover Castle post hundreds of photos and reviews daily across Instagram, Facebook, and TripAdvisor. Local businesses that could benefit from this exposure either have no social media presence or fail to engage with visitor content, missing an enormous free marketing opportunity."}, {"title": "Dormant Dover Facebook pages damaging business credibility", "description": "A potential customer searches for your Dover business on Facebook and finds a page last updated two years ago with inconsistent branding and no recent activity. This dormant presence is worse than no presence at all, actively signalling that the business may no longer be operating or does not care about its public image."}, {"title": "No social presence for community recommendation requests", "description": "Dover Facebook groups see daily posts asking for tradesperson recommendations, restaurant suggestions, and service provider referrals. Businesses without active, professional social media profiles cannot benefit from these recommendations because there is nothing credible for potential customers to check when they see your name mentioned."}]',
  '[{"title": "Tourist-intercepting social profiles for Dover hospitality", "description": "We set up and optimise Instagram and Facebook profiles designed to appear when visitors tag Dover locations. Proper hashtag strategy, location tagging, and content templates ensure your hospitality business benefits from the enormous volume of tourist content created around the White Cliffs and Castle daily."}, {"title": "Community-ready Facebook presence for Dover services", "description": "For trades and service businesses, we build Facebook profiles optimised for the Dover community conversation. Professional branding, complete service information, prominent reviews, and ready-to-share content that looks credible when someone recommends you in a local group and the prospect clicks through to check."}, {"title": "Branded, consistent profiles across every Dover-relevant platform", "description": "Facebook, Instagram, Google Business Profile, and LinkedIn where appropriate. Every profile carries consistent Dover-specific branding, complete business information, and platform-appropriate content. No orphaned profiles, no outdated information, no branding mismatches across platforms."}]',
  '[{"question": "Which social media platforms matter most for Dover businesses?", "answer": "It depends on your audience. Tourism and hospitality businesses benefit most from Instagram and TripAdvisor. Local service businesses need strong Facebook and Google Business Profiles for community engagement. B2B and logistics firms benefit from LinkedIn. We set up the platforms that match your specific Dover customer base."}, {"question": "Can social media really attract tourists to my Dover business?", "answer": "Yes. Visitors actively search Dover hashtags and location tags on Instagram and check Google reviews before choosing restaurants and activities. A professionally set up profile with strong visuals and positive reviews directly influences tourist spending. We have seen Dover hospitality clients significantly increase footfall through social presence alone."}, {"question": "How do I engage with tourist content about Dover?", "answer": "We set up monitoring for Dover-related hashtags, location tags, and mentions. When visitors post about the White Cliffs or Castle and tag nearby locations, your business can engage with that content, building visibility with their followers. We provide templates and guidance for effective engagement."}, {"question": "I do not have time to post on social media regularly. Can you help?", "answer": "Our service focuses on the professional setup and optimisation of your profiles, giving you a strong foundation. We also provide content templates and scheduling guidance that make posting take minutes rather than hours. For ongoing management, we can discuss regular content packages."}]',
  'trust'
)
