-- 9. Dover × AI Chatbots
INSERT INTO public.local_content (service_slug, town_slug, intro_paragraph, local_context, competition_landscape, success_approach, local_stats, pain_points, solutions, faqs, layout_variant)
VALUES (
  'ai-chatbots',
  'dover',
  'Dover businesses face an enquiry pattern that human staff simply cannot cover efficiently. Tourists planning White Cliffs walks ask the same questions about opening times, parking, and directions repeatedly. Guest houses receive identical booking enquiries at all hours from travellers across different time zones planning Channel crossings. Port logistics firms field routine availability and pricing questions that interrupt operational staff from their core work. A tradesperson driving between jobs across the Dover district misses calls from prospects who need immediate answers. AI chatbots solve all of these problems simultaneously. We build intelligent conversational assistants for Dover businesses that handle routine enquiries instantly, twenty-four hours a day, in multiple languages where needed, freeing your team to focus on the work that actually requires human attention and judgement.',
  'Dover''s enquiry patterns are shaped by its tourist and port economy. Hospitality businesses receive waves of identical questions about availability, location, parking near the Castle, and crossing-related timing. The port logistics sector handles repetitive quote requests and availability checks. Trades and service businesses across the district miss calls during working hours. The international dimension of Dover''s visitor base means enquiries arrive in multiple languages and across all time zones, creating a genuine twenty-four-hour demand that no small team can staff manually.',
  'AI chatbot adoption among Dover businesses is virtually non-existent. A handful of larger tourism operators use basic FAQ bots, but the technology has not penetrated the wider business community. This creates a significant first-mover advantage for early adopters. The businesses that implement intelligent chatbots now will capture enquiries that competitors are losing to phone queues, slow email responses, and closed-hours voicemails.',
  'We build Dover chatbots trained on your specific business knowledge and customer patterns. A guest house chatbot knows your room availability, proximity to the Castle and Cliffs, parking options, and ferry connection timing. A logistics chatbot handles quote requests and availability checks. A trades chatbot qualifies enquiries and books callbacks. Every chatbot is trained to recognise when a question requires human intervention and escalates seamlessly.',
  '{"population": 35000, "district_population": 117000, "business_districts": ["Market Square", "Port of Dover", "High Street", "De Bradelei Wharf"], "key_fact": "International visitors and port traffic create genuine 24-hour enquiry demand"}',
  '[{"title": "Repetitive tourist questions consuming Dover hospitality staff time", "description": "Dover hospitality businesses answer the same questions hundreds of times each season. Where is the nearest parking for the White Cliffs? How far is Dover Castle? What time does the last ferry leave? Each question takes staff time away from serving guests. Multiplied across peak season, this repetition consumes enormous operational capacity."}, {"title": "International enquiries arriving outside business hours", "description": "Travellers from mainland Europe and beyond plan Dover visits and Channel crossings from different time zones. Enquiries arrive at midnight, three in the morning, and during weekends. A guest house that cannot respond until nine the next morning loses the booking to a competitor with round-the-clock response capability."}, {"title": "Missed calls costing Dover trades businesses revenue", "description": "A tradesperson working at a property near Connaught Park cannot answer the phone when a new prospect calls from the town centre. The prospect calls the next number on their list. Without an intelligent system that can handle the initial enquiry, qualify the lead, and schedule a callback, Dover trades lose revenue every working day."}]',
  '[{"title": "Multilingual chatbots for Dover''s international visitor market", "description": "We build AI chatbots that handle enquiries in English, French, German, and other languages relevant to Dover''s international visitor base. A French tourist planning a post-crossing dinner can interact with your restaurant chatbot in their own language, receiving instant recommendations, availability, and booking confirmation."}, {"title": "Knowledge-trained assistants for Dover hospitality businesses", "description": "Your chatbot is trained on everything a guest needs to know: room details, proximity to the Castle and White Cliffs, parking options, ferry timing, restaurant recommendations, and local attractions. It handles the repetitive questions that consume your staff''s time, providing instant accurate answers twenty-four hours a day."}, {"title": "Lead-qualifying chatbots for Dover trades and services", "description": "We build chatbots that do more than answer questions. They qualify enquiries by asking about job scope, location, timing, and budget. A qualified lead with full details is delivered to your phone or email, ready for a precise quote. Unqualified tyre-kickers are filtered out before they consume your time."}]',
  '[{"question": "Can a chatbot really handle tourist questions about Dover?", "answer": "Yes. We train your chatbot with detailed knowledge about your business, local attractions, parking, directions, ferry connections, and everything tourists commonly ask. The chatbot provides instant, accurate answers that match what your best staff member would say. When a question falls outside its knowledge, it escalates to your team."}, {"question": "Will a chatbot work for my Dover logistics business?", "answer": "Absolutely. We build chatbots for logistics firms that handle routine quote requests, availability checks, and service enquiries. The chatbot collects structured information that your operations team can action immediately, eliminating the back-and-forth that delays quoting and frustrates potential clients."}, {"question": "Can the chatbot handle enquiries in French and other languages?", "answer": "Yes. Given Dover''s proximity to France and the volume of international visitors through the port, multilingual capability is a core feature. We configure chatbots to detect visitor language preference and respond accordingly, covering French, German, Dutch, and other languages relevant to your customer base."}, {"question": "What happens when the chatbot cannot answer a question?", "answer": "The chatbot recognises when a question exceeds its training and smoothly hands over to your team. It collects the visitor''s contact details and question, then notifies you via email or text. The customer receives a message confirming a team member will follow up, ensuring no enquiry is lost."}]',
  'authority'
)
ON CONFLICT (service_slug, town_slug) DO UPDATE SET
  intro_paragraph = EXCLUDED.intro_paragraph,
  local_context = EXCLUDED.local_context,
